interiorAirFilter_modId12_shortDes_crit1 = TextObject(bs_BA="Trenutno nema poruka.", cs_CZ="Momentálně nejsou žádné zprávy.", da_DK="Ingen meddelelser p.t.", de_DE="Zurzeit gibt es keine Meldungen.", el_GR="Προς το παρόν δεν υπάρχουν μηνύματα.", en_GB="There are currently no notifications.", es_ES="No hay mensajes actualmente.", fi_FI="Ilmoituksia ei tällä hetkellä ole.", fr_FR="Aucun message actuellement.", hr_HR="Trenutačno nema obavijesti.", hu_HU="Jelenleg nincs üzenet.", it_IT="Al momento non ci sono messaggi.", nl_NL="Er zijn momenteel geen meldingen.", no_NO="Du har ingen meldinger nå.", pl_PL="Obecnie brak komunikatów.", pt_PT="De momento não existem indicações.", ro_RO="Momentan nu există mesaje.", ru_RU="В настоящее время нет сообщений.", sk_SK="Momentálne nie sú žiadne hlásenia.", sl_SI="Trenutno ni nobenih obvestil.", sr_RS="Trenutno nema poruka.", sv_SE="Det finns inga meddelanden just nu.", tr_TR="Şu anda herhangi bir bildirim yok.", uk_UA="Наразі немає жодних повідомлень.")
