models_inspection_oil_name = TextObject(bs_BA="Inspekcija i zamjena ulja", cs_CZ="Kontrola a výměna oleje", da_DK="Serviceeftersyn og olieskift", de_DE="Inspektion und Ölwechsel", el_GR="Επιθεώρηση και αλλαγή λαδιών", en_GB="Inspection and oil change", es_ES="Inspección y cambio de aceite", fi_FI="Tarkastushuolto ja öljynvaihto", fr_FR="Révision et vidange d'huile", hr_HR="Inspekcijski servis i servis zamjene ulja", hu_HU="Ellenőrző szerviz és olajcsere", it_IT="Ispezione e cambio olio", nl_NL="Inspectie en olie verversen", no_NO="Inspeksjon og oljeskift", pl_PL="Przegląd i wymiana oleju", pt_PT="Revisão e troca de óleo", ro_RO="Inspecţie şi schimb de ulei", ru_RU="Инспекция и замена масла", sk_SK="Prehliadka a výmena oleja", sl_SI="Servisni pregled in menjava olja", sr_RS="Inspekcija i zamena ulja", sv_SE="Service och oljebyte", tr_TR="Kontrol ve yağ değişimi", uk_UA="Інспекція та заміна масла")
models_inspection_summary_crit1 = TextObject(bs_BA="Inspekcija još nije dospjela", cs_CZ="Kontrola ještě neproběhla", da_DK="Det er ikke tid til serviceeftersyn endnu.", de_DE="Inspektion noch nicht fällig", el_GR="Η επιθεώρηση δεν επίκειται ακόμη άμεσα", en_GB="Inspection not yet due", es_ES="El plazo para la inspección no ha vencido todavía", fi_FI="Tarkastushuolto ei vielä ajankohtainen", fr_FR="Révision pas encore arrivée à échéance", hr_HR="Inspekcijski servis još nije dospio", hu_HU="Ellenőrző szerviz még nem esedékes", it_IT="Ispezione non ancora in scadenza", nl_NL="Inspectie nog niet nodig", no_NO="Det er ikke tid for inspeksjon ennå", pl_PL="Termin przeglądu jeszcze nie nadszedł", pt_PT="Ainda não está na altura da revisão", ro_RO="Inspecţia nu este scadentă încă", ru_RU="Инспекция еще не необходима", sk_SK="Prehliadka ešte nie je aktuálna", sl_SI="Servisni pregled še ni zapadel", sr_RS="Inspekcija još nije dospela", sv_SE="Inte dags för service än", tr_TR="Kontrol zamanı henüz gelmedi", uk_UA="Інспекція ще не необхідна")
models_manualReset_disclaimer = TextObject(bs_BA="Ovu tačku provjere označite kao završenu tek nakon što je obavljen\nservis. Status tačke provjere se na taj način resetuje. Ovaj\npostupak se ne može poništiti.", cs_CZ="Označte tento kontrolní bod jako dokončený až po provedení\nslužby. Tím se resetuje stav kontrolního bodu. Tento proces nelze\nvrátit zpět.", da_DK="Marker kun dette kontrolpunkt som afsluttet, når servicen er\ngennemført. Statussen for kontrolpunktet nulstilles derved.\nDenne handling kan ikke fortrydes.", de_DE="Bitte markiere diesen Prüfpunkt nur als erledigt, nachdem der\nService durchgeführt wurde. Der Status des Prüfpunktes wird\ndadurch zurückgesetzt.\nDieser Vorgang kann nicht rückgängig gemacht werden.", el_GR="Επισημάνετε αυτό το σημείο ελέγχου ως διεκπεραιωμένο, μόνον\nαφού πραγματοποιηθεί το Service. Έτσι γίνεται επαναφορά (reset)\nτου σημείου ελέγχου. Αυτή η διαδικασία δεν μπορεί να αναιρεθεί.", en_GB="Please only mark this inspection item as completed after a service\nhas been performed. This will reset the status of the inspection\nitem. It is not possible to undo this process.", es_ES="Por favor, marque este punto de comprobación como realizado\nsolo después de realizar el Servicio. Cuando lo haga, se\nrestablecerá el estado del punto de comprobación. Esta operación\nno se puede deshacer.", fi_FI="Merkitse tämä tarkastuskohde tehdyksi vasta sen jälkeen, kun\nhuolto on tehty. Merkitseminen nollaa tarkastuskohteen tilan.\nTätä toimintoa ei voi kumota.", fr_FR="Veuillez ne marquer ce point de contrôle comme terminé qu'après\nla réalisation de l'entretien. L'état du point de contrôle est ainsi\nréinitialisé. Ce processus ne peut pas être annulé.", hr_HR="Označite ovu ispitnu točku kao riješenu tek nakon provedbe\nservisa. Status ispitne točke na taj se način vraća na početni. Ovaj\nse postupak ne može poništiti.", hu_HU="Kérünk, csak a szerviz elvégzése után jelöld ezt az ellenőrzési\npontot befejezettnek. Ez visszaállítja az ellenőrzési pont\nstátuszát. A folyamat nem vonható vissza.", it_IT="Segnare questo punto di controllo come completato solo dopo\nl'esecuzione dell'intervento previsto. In questo modo lo stato del\npunto di controllo verrà azzerato. Questa operazione non potrà\nessere annullata.", nl_NL="Markeer dit controlepunt pas als voltooid nadat het onderhoud is\nuitgevoerd. Hiermee wordt de status van het controlepunt\ngereset. Dit proces kan niet ongedaan worden gemaakt.", no_NO="Vent til servicen er utført før du merker kontrollpunktet som\nutført. Da tilbakestilles statusen for kontrollpunktet. Handlingen\nkan ikke angres.", pl_PL="Zaznacz ten punkt kontrolny jako zrealizowany dopiero po\nwykonaniu serwisu. Spowoduje to zresetowanie statusu punktu\nkontrolnego. Tego procesu nie można cofnąć.", pt_PT="Este ponto de verificação só deve ser marcado como realizado\napós o serviço ter sido realizado. O estado do ponto de verificação\né reposto. Este procedimento não pode ser revertido.", ro_RO="Marcaţi acest punct de verificare ca fiind realizat numai după ce a\nfost realizată lucrarea de service. Astfel este resetată starea\npunctului de verificare. Acest proces nu poate fi revocat.", ru_RU="Отметьте этот контрольный пункт как выполненный только\nпосле выполнения обслуживания. Это сбрасывает статус\nконтрольной точки. Этот процесс нельзя отменить.", sk_SK="Prosím, označte tento kontrolný bod ako dokončený až potom,\nako sa vykonal servis. Stav kontrolného bodu sa tým resetuje.\nTento proces nie je možné vrátiť späť.", sl_SI="To kontrolno točko označite za opravljeno le, ko je bil servis\nopravljen. Status kontrolne točke bo s tem resetiran. Tega\npostopka ni mogoče razveljaviti.", sr_RS="Označite ovu tačku provere kao završenu tek nakon što je izvršen\nservis. Status tačke provere se, na taj način, resetuje. Ovaj\npostupak ne može da se poništi.", sv_SE="Markera denna kontrollpunkt som utförd först när service har\ngenomförts. Detta återställer kontrollpunktens status. Processen\nkan inte ångras.", tr_TR="Lütfen bu kontrol noktasını sadece servis gerçekleştirildikten\nsonra tamamlandı olarak işaretle. Bu şekilde kontrol noktasının\ndurumu sıfırlanır. Bu işlem geri alınamaz.", uk_UA="Будь ласка, позначайте цей контрольний пункт як завершений\nлише після того, як служба буде виконана. Це призведе до\nобнулення статусу контрольного пункту. Цей процес не може\nбути скасований.")
models_manualReset_title = TextObject(bs_BA="%1: Kada je izvršen servis?", cs_CZ="%1: Kdy byla servisní služba provedena?", da_DK="%1: Hvornår blev service udført?", de_DE="%1: Wann wurde der Service durchgeführt?", el_GR="%1: Πότε πραγματοποιήθηκε το Service;", en_GB="%1: When was the service performed?", es_ES="%1: ¿Cuándo se realizó el Servicio?", fi_FI="%1: milloin huolto tehtiin?", fr_FR="%1: quand l'entretien a-t-il été effectué?", hr_HR="%1: kada je proveden servis?", hu_HU="%1: Mikor hajtották végre a szervizt?", it_IT="%1: quando è stato eseguito l'intervento di assistenza?", nl_NL="%1: wanneer is de service uitgevoerd?", no_NO="%1: Når ble servicen utført?", pl_PL="%1: kiedy został przeprowadzony serwis?", pt_PT="%1: Quando foi realizado o serviço?", ro_RO="%1: când a fost realizată lucrarea de service?", ru_RU="%1: когда было проведено техобслуживание?", sk_SK="%1: kedy bol servis vykonaný?", sl_SI="%1: kdaj je bil servis opravljen?", sr_RS="%1: Kada je izvršen servis?", sv_SE="%1: När genomfördes service?", tr_TR="%1: Servis ne zaman yapıldı?", uk_UA="%1: коли був проведений сервіс?")
models_markAsDone_title = TextObject(bs_BA="%1: Označiti kao završeno", cs_CZ="%1: Označit jako vyřízené", da_DK="%1: Marker som afsluttet", de_DE="%1: Als erledigt markieren", el_GR="%1: Επισήμανση ως διεκπεραιωθέν", en_GB="%1: Mark as completed", es_ES="%1: Marcar como realizado", fi_FI="%1: merkitse tehdyksi", fr_FR="%1: marquer comme terminé", hr_HR="%1: označiti kao riješeno", hu_HU="%1: Jelölés befejezettnek", it_IT="%1: segna come completato", nl_NL="%1: markeren als voltooid", no_NO="%1: Merk som utført", pl_PL="%1: oznacz jako zrealizowany", pt_PT="%1: Marcar como concluído", ro_RO="%1: marcare ca rezolvat", ru_RU="%1: отметить как выполненный", sk_SK="%1: označiť ako vybavený", sl_SI="%1: označi kot opravljeno", sr_RS="%1: Označiti kao završeno", sv_SE="%1: Markera som utförd", tr_TR="%1: Tamamlandı olarak işaretle", uk_UA="%1: позначити як завершений")
models_noResults = TextObject(bs_BA="Nema poruka", cs_CZ="Žádné zprávy", da_DK="Ingen meddelelser", de_DE="Keine Meldungen", el_GR="Δεν υπάρχουν μηνύματα", en_GB="No notifications", es_ES="No hay mensajes", fi_FI="Ei ilmoituksia", fr_FR="Aucun message", hr_HR="Nema obavijesti", hu_HU="Nincs üzenet", it_IT="Nessun messaggio", nl_NL="Geen meldingen", no_NO="Ingen meldinger", pl_PL="Brak komunikatów", pt_PT="Sem mensagens", ro_RO="Nu există mesaje", ru_RU="Нет сообщений", sk_SK="Žiadne hlásenia", sl_SI="Ni obvestil", sr_RS="Nema poruka", sv_SE="Inga meddelanden", tr_TR="Hiçbir bildirim yok", uk_UA="Немає повідомлень")
models_oil_description_crit1 = TextObject(bs_BA="Ovdje se možete unaprijed informirati o predstojećoj zamjeni ulja. U slučaju pitanja se uvijek možete obratiti Vašem\nAudi partneru.", cs_CZ="Zde se můžete předem informovat o nadcházející výměně oleje. V případě dotazů se můžete kdykoli obrátit na\nsvého partnera Audi.", da_DK="Her kan få information om det forestående olieskift på forhånd. Hvis du har spørgsmål, kan du til enhver tid\nhenvende dig til din Audi partner.", de_DE="Hier kannst du dich vorab über den anstehenden Ölwechsel informieren. Bei Fragen kannst du dich jederzeit bei\ndeinem Audi Partner melden.", el_GR="Εδώ μπορείτε να ενημερωθείτε εκ των προτέρων για την επικείμενη αλλαγή λαδιών. Εάν έχετε ερωτήσεις, μπορείτε\nανά πάσα στιγμή να επικοινωνήσετε με τον εξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί.", en_GB="You can find information about the upcoming oil change in advance here. You can contact your Audi Partner at any\ntime if you have any questions.", es_ES="Aquí puede informarse con antelación sobre el cambio de aceite inminente. Si tiene dudas, puede ponerse en\ncontacto con su Concesionario Audi en todo momento.", fi_FI="Tässä voit tutustua etukäteen tulevaan öljynvaihtoon. Jos sinulla on kysyttävää, voit milloin tahansa ottaa yhteyttä\nAudi-jälleenmyyjääsi.", fr_FR="Ici, vous pouvez vous informer à l'avance sur la vidange d'huile à venir. Si vous avez des questions, vous pouvez à\ntout moment contacter votre Partenaire Audi.", hr_HR="Tu se možete unaprijed informirati o predstojećem servisu zamjene ulja. U slučaju pitanja u svakom se trenutku\nmožete obratiti svom Audi partneru.", hu_HU="Itt tájékozódhatsz előzetesen az esedékes olajcseréről. Ha kérdésed van, bármikor felveheted a kapcsolatot Audi\npartnereddel.", it_IT="Qui è possibile ottenere informazioni in anticipo sul prossimo cambio dell'olio. In caso di domande, può contattare\nil Suo partner Audi in qualsiasi momento.", nl_NL="Hier kun je van tevoren informatie krijgen over de komende olieverversing. Bij vragen kun je altijd contact opnemen\nmet je Audi-partner.", no_NO="Her kan du se informasjon om det kommende oljeskiftet. Kontakt Audi-verkstedet hvis du har spørsmål.", pl_PL="Informacje o zbliżającej się wymianie oleju można znaleźć tutaj. Jeśli masz jakieś pytania, możesz w każdej chwili\nskontaktować się z dealerem Audi.", pt_PT="Aqui podes informar-te previamente sobre a troca de óleo pendente. Em caso de dúvidas podes contactar o teu\nConcessionário Audi em qualquer altura.", ro_RO="Aici vă puteţi informa în prealabil cu privire la schimbul de ulei scadent. Dacă aveţi întrebări vă puteţi adresa în orice\nmoment partenerului Audi.", ru_RU="Здесь вы можете заранее узнать о предстоящей замене масла. Если у вас возникнут вопросы, вы можете в\nлюбое время обратиться к партнеру Audi.", sk_SK="Tu sa môžete vopred informovať o nastávajúcej výmene oleja. V prípade otázok sa môžete kedykoľvek ohlásiť u\nsvojho partnera Audi.", sl_SI="Tukaj se lahko predhodno seznanite s potrebno menjavo olja. V primeru vprašanj se lahko kadar koli obrnete na\npooblaščenega partnerja Audi.", sr_RS="Ovde se možete unapred informisati o predstojećoj zameni ulja. U slučaju pitanja uvek se možete obratiti vašem\nAudi partneru.", sv_SE="Här hittar du information om ett kommande oljebyte. Du kan alltid kontakta din Audi-partner vid frågor.", tr_TR="Burada yaklaşmakta olan yağ değişimi hakkında önceden bilgi edinebilirsin. Herhangi bir sorun varsa Audi yetkili\nservisin ile istediğiniz zaman iletişime geçebilirsin.", uk_UA="Ви можете заздалегідь дізнатися про майбутню заміну масла тут. Якщо у вас виникнуть запитання, ви можете\nзвернутися до свого партнера Audi в будь-який час.")
models_oil_description_crit2 = TextObject(bs_BA="Uskoro predstoji sljedeća zamjena ulja. U slučaju pitanja se uvijek možete obratiti Vašem Audi partneru.", cs_CZ="Další výměna oleje se blíží. V případě dotazů se můžete kdykoli obrátit na svého partnera Audi.", da_DK="Næste olieskift er forestående. Hvis du har spørgsmål, kan du til enhver tid henvende dig til din Audi partner.", de_DE="Der nächste Ölwechsel steht bevor. Bei Fragen kannst du dich jederzeit bei deinem Audi Partner melden.", el_GR="Επίκειται η επόμενη αλλαγή λαδιών. Εάν έχετε ερωτήσεις, μπορείτε ανά πάσα στιγμή να επικοινωνήσετε με τον\nεξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί.", en_GB="The next oil change is coming up. You can contact your Audi Partner at any time if you have any questions.", es_ES="El próximo cambio de aceite es inminente. Si tiene dudas, puede ponerse en contacto con su Concesionario Audi en\ntodo momento.", fi_FI="Seuraava öljynvaihto lähestyy. Jos sinulla on kysyttävää, voit milloin tahansa ottaa yhteyttä Audi-jälleenmyyjääsi.", fr_FR="La prochaine vidange d'huile arrive bientôt à échéance. Si vous avez des questions, vous pouvez à tout moment\ncontacter votre Partenaire Audi.", hr_HR="Predstoji sljedeći servis zamjene ulja. U slučaju pitanja u svakom se trenutku možete obratiti svom Audi partneru.", hu_HU="Közeledik a következő olajcsere. Ha kérdésed van, bármikor felveheted a kapcsolatot Audi partnereddel.", it_IT="A breve sarà necessario sostituire l'olio. In caso di domande, può contattare il Suo partner Audi in qualsiasi momento.", nl_NL="De volgende olieverversing staat voor de deur. Bij vragen kun je altijd contact opnemen met je Audi-partner.", no_NO="Det er snart tid for neste oljeskift. Kontakt Audi-verkstedet hvis du har spørsmål.", pl_PL="Zbliża się następna wymiana oleju. Jeśli masz jakieś pytania, możesz w każdej chwili skontaktować się z dealerem\nAudi.", pt_PT="A próxima troca de óleo está para breve. Em caso de dúvidas podes contactar o teu Concessionário Audi em\nqualquer altura.", ro_RO="Următorul schimb de ulei este scadent. Dacă aveţi întrebări vă puteţi adresa în orice moment partenerului Audi.", ru_RU="Следующая замена масла уже скоро. Если у вас возникнут вопросы, вы можете в любое время обратиться к\nсвоему партнеру Audi.", sk_SK="Nasledujúca výmena oleja čoskoro nastane. V prípade otázok sa môžete kedykoľvek ohlásiť u svojho partnera Audi.", sl_SI="Naslednja menjava olja se bliža. V primeru vprašanj se lahko kadar koli obrnete na pooblaščenega partnerja Audi.", sr_RS="Sledeća zamena ulja neposredno predstoji. U slučaju pitanja, uvek se možete obratiti vašem Audi partneru.", sv_SE="Det är snart dags för oljebyte. Du kan alltid kontakta din Audi-partner vid frågor.", tr_TR="Bir sonraki yağ değişimi yaklaşıyor. Herhangi bir sorun varsa Audi yetkili servisin ile istediğiniz zaman iletişime\ngeçebilirsin.", uk_UA="Наступна заміна масла вже скоро. Якщо у вас виникнуть запитання, ви можете в будь-який час звернутися до\nсвого партнера Audi.")
models_oil_description_crit4 = TextObject(bs_BA="Sljedeća zamjena ulja se treba izvršiti što je prije moguće. U slučaju pitanja se uvijek možete obratiti Vašem Audi partneru.", cs_CZ="Další výměna oleje by měla být provedena co nejdříve. V případě dotazů se můžete kdykoli obrátit na svého partnera Audi.", da_DK="Næste olieskift bør gennemføres så snart som muligt. Hvis du har spørgsmål, kan du til enhver tid henvende dig til\ndin Audi partner.", de_DE="Der nächste Ölwechsel sollte sobald wie möglich durchgeführt werden. Bei Fragen kannst du dich jederzeit bei\ndeinem Audi Partner melden.", el_GR="Θα πρέπει να πραγματοποιηθεί η επόμενη αλλαγή λαδιών όσο το δυνατόν συτνομότερα. Εάν έχετε ερωτήσεις,\nμπορείτε ανά πάσα στιγμή να επικοινωνήσετε με τον εξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί.", en_GB="The next oil change should be performed as soon as possible. You can contact your Audi Partner at any time if you\nhave any questions.", es_ES="El próximo cambio de aceite debería realizarse lo antes posible. Si tiene dudas, puede ponerse en contacto con su\nConcesionario Audi en todo momento.", fi_FI="Seuraava öljynvaihto on tehtävä niin pian kuin mahdollista. Jos sinulla on kysyttävää, voit milloin tahansa ottaa\nyhteyttä Audi-jälleenmyyjääsi.", fr_FR="La prochaine vidange d'huile doit être effectuée dès que possible. Si vous avez des questions, vous pouvez à tout\nmoment contacter votre Partenaire Audi.", hr_HR="Sljedeći servis zamjene ulja trebalo bi provesti čim prije. U slučaju pitanja u svakom se trenutku možete obratiti\nsvom Audi partneru.", hu_HU="A következő olajcserét a lehető leghamarabb el kell végezni. Ha kérdésed van, bármikor felveheted a kapcsolatot\nAudi partnereddel.", it_IT="Il prossimo cambio dell'olio deve essere effettuato il prima possibile. In caso di domande, può contattare il Suo\npartner Audi in qualsiasi momento.", nl_NL="De volgende olieverversing moet zo snel mogelijk worden uitgevoerd. Bij vragen kun je altijd contact opnemen met\nje Audi-partner.", no_NO="Neste oljeskift bør utføres så snart som mulig. Kontakt Audi-verkstedet hvis du har spørsmål.", pl_PL="Następną wymianę oleju należy przeprowadzić jak najszybciej. Jeśli masz jakieś pytania, możesz w każdej chwili\nskontaktować się z dealerem Audi.", pt_PT="A próxima troca de óleo deve ser realizada com a maior brevidade possível. Em caso de dúvidas podes contactar o\nteu Concessionário Audi em qualquer altura.", ro_RO="Următorul schimb de ulei trebuie realizat cât mai curând. Dacă aveţi întrebări vă puteţi adresa în orice moment\npartenerului Audi.", ru_RU="Следующую замену масла следует провести как можно скорее. Если у вас возникли вопросы, вы можете в\nлюбое время обратиться к своему партнеру Audi.", sk_SK="Nasledujúca výmena oleja by sa mala uskutočniť čo najskôr. V prípade otázok sa môžete kedykoľvek ohlásiť u svojho\npartnera Audi.", sl_SI="Naslednjo menjavo olja je treba opraviti čim prej. V primeru vprašanj se lahko kadar koli obrnete na pooblaščenega\npartnerja Audi.", sr_RS="Sledeća zamena ulja treba da se izvrši što je pre moguće. U slučaju pitanja, uvek se možete obratiti vašem Audi partneru.", sv_SE="Nästa oljebyte bör genomföras så snart som möjligt. Du kan alltid kontakta din Audi-partner vid frågor.", tr_TR="Bir sonraki yağ değişimi mümkün olan en kısa sürede gerçekleştirilmelidir. Herhangi bir sorun varsa Audi yetkili\nservisin ile istediğiniz zaman iletişime geçebilirsin.", uk_UA="Наступну заміну масла слід провести якомога швидше. Якщо у вас виникнуть запитання, ви можете в будь-який\nчас звернутися до свого партнера Audi.")
models_oil_infotext = TextObject(bs_BA="Motorno ulje ima suštinski uticaj na efikasnost i funkciju motora. U cilju osiguranja pouzdanog podmazivanja\nmotora, potrebno je izvršavati zamjenu ulja unutar preporučenih intervala.\n\nNapominjemo da ova funkcija služi isključivo kao podrška i podsjetnik. Za pravilan unos i blagovremeno izvođenje\nneophodnih obima održavanja, isključivu odgovornost i dalje imate Vi.", cs_CZ="Motorový olej hraje klíčovou roli v účinnosti a funkci motoru. Aby bylo zajištěno spolehlivé mazání vašeho motoru,\nměli byste olej měnit v doporučených intervalech.\n\nUpozorňujeme, že tato funkce je určena výhradně pro účely podpory a připomenutí. Zodpovídáte za správné zadání\ninformací a včasné dodržování požadované údržby.", da_DK="Motorolien spiller en afgørende rolle for motorens virkning og funktion. For at sikre en pålidelig smøring af din\nmotor bør du få gennemført olieskift inden for de anbefalede intervaller.\n\nVær opmærksom på, at denne funktion kun er til ren hjælp og påmindelse. Du er stadig selv ansvarlig for korrekte\nangivelser og rettidig overholdelse af det påkrævede servicearbejde.", de_DE="Das Motoröl ist maßgeblich an der Wirkung und Funktion des Motors beteiligt. Zur Sicherstellung der zuverlässigen\nSchmierung deines Motors solltest du den Ölwechsel innerhalb der empfohlenen Intervalle durchführen lassen.\n\nBitte beachte, dass diese Funktion nur zur reinen Unterstützung und Erinnerung dient. Für die korrekte Eingabe\nund das rechtzeitige Einhalten der erforderlichen Wartungsumfänge bist du weiterhin selbst verantwortlich.", el_GR="Το λάδι του κινητήρα παίζει καθοριστικό ρόλο στις επιδόσεις και τη λειτουργία του κινητήρα. Για τη διασφάλιση της\nαξιόπιστης λίπανσης του κινητήρα σας, θα πρέπει να αλλάζετε το λάδι εντός των συνιστώμενων διαστημάτων.\n\nΈχετε υπόψη ότι αυτή η λειτουργία χρησιμεύει μόνο στην υποστήριξη και υπενθύμιση. Εξακολουθείτε να είστε οι ίδιοι\nυπεύθυνοι για τη σωστή καταχώριση και την έγκαιρη τήρηση των απαιτούμενων εργασιών συντήρησης.", en_GB="The engine oil plays an essential role in engine functionality. To ensure that your engine is lubricated reliably, you\nshould have the oil change performed within the recommended intervals.\n\nPlease note that this is only a support and reminder function. You remain responsible for ensuring that the required\nmaintenance items are entered correctly and complied with on time.", es_ES="El aceite del motor desempeña un papel fundamental en el rendimiento y el funcionamiento del motor. Para\ngarantizar que la lubricación del motor sea correcta, debería realizar el cambio de aceite dentro de los intervalos\nrecomendados.\n\nPor favor, tenga en cuenta que esta función solo sirve de apoyo y recordatorio. Usted sigue siendo\nresponsable de introducir correctamente los trabajos de mantenimiento requeridos y de realizarlos a tiempo.", fi_FI="Moottoriöljyllä on tärkeä merkitys moottorin toiminnalle. Moottoriöljy on vaihdettava suositelluin väliajoin\nmoottorin kunnollisen voitelun varmistamiseksi.\n\nHuomaa, että tämä toiminto on tarkoitettu vain tueksi ja muistutukseksi. Olet aina itse vastuussa tietojen\noikeellisuudesta sekä tarvittavien huoltojen määräaikojen noudattamisesta.", fr_FR="L'huile-moteur joue un rôle déterminant dans l'efficacité et le fonctionnement du moteur. Pour garantir la\nlubrification fiable de votre moteur, il est recommandé de faire effectuer la vidange d'huile dans les intervalles\nrecommandés.\n\nVeuillez noter que cette fonction n'est fournie qu'à titre d'assistance et de rappel. Vous demeurez\nresponsable de la saisie correcte et du respect en temps voulu des travaux d'entretien nécessaires.", hr_HR="Motorno ulje u znatnoj mjeri pridonosi učinkovitosti i funkciji motora. Kako bi se zajamčilo pouzdano podmazivanje\nvašeg motora, trebali biste dati zamijeniti ulje unutar preporučenih intervala.\n\nImajte na umu da ova funkcija služi samo kao potpora i podsjetnik. Za pravilan unos i pravovremenu provedbu\npotrebnih opsega održavanja i dalje sami snosite odgovornost.", hu_HU="A motorolaj kulcsszerepet játszik a motor teljesítményében és működésében. A motor megbízható kenésének\nbiztosítása érdekében az olajcserét az ajánlott időközönként kell elvégeztetni.\n\nKérünk, vedd figyelembe, hogy ez a funkció csak támogatási és emlékeztető célokat szolgál. A szükséges\nkarbantartási munkák helyes megadásáért és megfelelő időben történő teljesítéséért továbbra is Te vagy a felelős.", it_IT="L'olio motore svolge un ruolo fondamentale per le prestazioni e il funzionamento del motore. Per garantire la\nlubrificazione affidabile del motore, è necessario far eseguire il cambio dell'olio entro gli intervalli raccomandati.\n\nSi prega di tenere presente che questa funzione serve esclusivamente come supporto e promemoria. L'utente resta\nsempre responsabile dell'inserimento corretto e dell'esecuzione puntuale degli interventi di manutenzione\nnecessari.", nl_NL="De motorolie speelt een belangrijke rol in de prestaties en werking van de motor. Om een betrouwbare smering van\nje motor te garanderen, moet je de olie binnen de aanbevolen intervallen laten verversen.\n\nHoud er rekening mee dat deze functie alleen ter ondersteuning en herinnering dient. Je blijft zelf verantwoordelijk\nvoor het correct invoeren van de gegevens en het tijdig laten uitvoeren van het benodigde onderhoud.", no_NO="Motoroljen er avgjørende for at motoren skal fungere optimalt. Du bør få skiftet motorolje innenfor de anbefalte\nintervallene for å sikre god smøring av motoren.\n\nMerk at denne funksjonen bare er ment som hjelp og påminnelse.\nDu er selv ansvarlig for å legge inn korrekte opplysninger og sørge for at vedlikeholdsarbeid utføres til rett tid.", pl_PL="Olej silnikowy odgrywa kluczową rolę w działaniu i funkcjonowaniu silnika. Aby zapewnić niezawodne smarowanie\nsilnika, olej należy wymieniać w zalecanych odstępach czasu.\n\nNależy pamiętać, że ta funkcja służy wyłącznie do celów pomocniczych i przypominania. Za prawidłowe wpisanie i\nterminowe wykonanie wymaganego zakresu konserwacji w dalszym ciągu odpowiada użytkownik.", pt_PT="O óleo do motor tem uma influencia muito grande na performance e funcionamento do motor.Para assegurar a\neficaz lubrificação do motor, é necessário realizar a troca de óleo dentro dos intervalos recomendados.\n\nAtenção que esta função tem uma função apenas de auxílio e recordatória. És tu o responsável pela introdução e\ncumprimento atempado dos necessários âmbitos de manutenção.", ro_RO="Uleiul de motor are o contribuţie semnificativă la randamentul şi funcţionarea motorului. Pentru asigurarea gresării\nsigure a motorului, trebuie să dispuneţi efectuarea schimbului de ulei la intervalele recomandate.\n\nReţineţi că această funcţie are doar rol de asistenţă şi reamintire. Pentru introducerea corectă şi realizarea la timp a\nconţinuturilor lucrărilor de întreţinere necesare sunteţi responsabil în continuare dumneavoastră.", ru_RU="Моторное масло играет ключевую роль в работе и функционировании двигателя. Чтобы обеспечить надежную\nсмазку двигателя, необходимо менять масло через рекомендованные промежутки времени.\nОбратите внимание, что эта функция предназначена только для поддержки и напоминания. Вы по-прежнему несете\nответственность за правильный ввод и своевременное выполнение требуемого объема технического\nобслуживания.", sk_SK="Motorový olej je podstatný pri výkone a funkcii motora. Aby ste zabezpečili spoľahlivé mazanie motora, mali by ste\nolej meniť v odporúčaných intervaloch.\n\nProsím pamätajte na to, že táto funkcia slúži výlučne na podporu a ako pripomienka. Za správne zadanie a včasné\nsplnenie požadovaných intervalov údržby ste stále zodpovední vy.", sl_SI="Motorno olje odločilno vpliva na učinek in delovanje motorja. Za zagotavljanje zanesljivega mazanja motorja morate\nmotorno olje menjati v priporočenih intervalih.\n\nUpoštevajte, da je ta funkcija namenjena zgolj v podporo in kot opomnik. Za pravilen vnos in pravočasno\nupoštevanje potrebnega obsega vzdrževanja ste še naprej odgovorni sami.", sr_RS="Ulje motora ima jednu od ključnih uloga za efikasnost i funkciju motora. U cilju obezbeđenja pouzdanog\npodmazivanja motora, potrebno je izvršiti zamenu ulja u okviru preporučenih intervala.\n\nNapominjemo da ova funkcija služi samo kao podrška i podsetnik. Za pravilan unos i blagovremeno izvođenje\nneophodnih održavanja odgovornost i dalje imate vi.", sv_SE="Motoroljan har stor inverkan på motorns verkningsgrad och funktion. För att säkerställa god smörjning av motorn\nbör du genomföra oljebyte inom de rekommenderade intervallen.\n\nObservera att funktionen endast är till som stöd och påminnelse. Du ansvarar själv för att uppdatera informationen\noch låta genomföra den service som krävs.", tr_TR="Motor yağı, motorun etki ve işlevinde önemli bir rol oynar. Motorunun güvenilir bir şekilde yağlanmasını sağlamak\niçin yağ değişimini önerilen aralıklar içinde yaptırmalısın.\n\nLütfen bu fonksiyonun tamamen destek ve hatırlatma amaçlı olduğunu dikkate al. Bilgilerin doğru girilmesi ve\ngerekli bakım kapsamlarının zamanında yapılması hala senin sorumluluğunudadır.", uk_UA="Моторна олива відіграє ключову роль у продуктивності та функціонуванні двигуна. Щоб забезпечити надійне\nзмащення двигуна, слід замінювати оливу відповідно до рекомендованих інтервалів. Зверніть увагу, що ця\nфункція призначена лише для підтримки та нагадування. Ви, як і раніше, несете відповідальність за\nправильний запис і своєчасне виконання необхідного обсягу технічного обслуговування.")
models_oil_name = TextObject(bs_BA="Ulje motora", cs_CZ="Motorový olej", da_DK="Motorolie", de_DE="Motoröl", el_GR="Λάδι κινητήρα", en_GB="Engine oil", es_ES="Aceite del motor", fi_FI="Moottoriöljy", fr_FR="Huile-moteur", hr_HR="Motorno ulje", hu_HU="Motorolaj", it_IT="Olio motore", nl_NL="Motorolie", no_NO="Motorolje", pl_PL="Olej silnikowy", pt_PT="Óleo do motor", ro_RO="Ulei de motor", ru_RU="Моторное масло", sk_SK="Motorový olej", sl_SI="Motorno olje", sr_RS="Ulje motora", sv_SE="Motorolja", tr_TR="Motor yağı", uk_UA="Моторна олива")
