rd_serviceLead_resolveProblem_title = TextObject(bs_BA="Otklanjanje greške iz daljinske dijagnoze vozila", cs_CZ="Opravte chyby ze vzdálené diagnostiky vozidla", da_DK="Afhjælp fejl fra bilfjerndiagnose", de_DE="Fehler aus der Fahrzeug-Ferndiagnose beheben", el_GR="Επισκευή βλαβών από την απομακρυσμένη διάγνωση οχήματος", en_GB="Remedy faults from remote vehicle diagnostics", es_ES="Solucionar errores detectados por la diagnosis remota vehículo", fi_FI="Korjaa vika auton etädiagnoosista", fr_FR="Éliminer les défauts issus du diagnostic à distance du véhicule", hr_HR="Ukloniti grešku iz dijagnoze vozila na daljinu", hu_HU="Hiba elhárítása a jármű-távdiagnosztikából", it_IT="Risoluzione dei problemi della diagnosi vettura a distanza", nl_NL="Fout van voertuigdiagnose op afstand corrigeren", no_NO="Utbedre feil fra fjerndiagnosen av bilen", pl_PL="Wyeliminuj błąd ze zdalnej diagnostyki pojazdu", pt_PT="Corrigir falha no diagnóstico remoto do veículo", ro_RO="Remediere eroare din telediagnoza autovehiculului", ru_RU="Исправление ошибок при удаленной диагностике автомобиля", sk_SK="Odstrániť chybu zo vzdialenej diagnostiky vozidla", sl_SI="Odprava napake iz telediagnoze vozila", sr_RS="Otklanjanje greške iz daljinske dijagnostike vozila", sv_SE="Åtgärda fel från fjärrdiagnosen", tr_TR="Araç uzaktan teşhisindeki hataları düzeltin", uk_UA="Виправити помилки дистанційної діагностики автомобіля")
