rd_yellow_singleWarning_title = TextObject(bs_BA="Tehnički događaj: Kontaktirati Audi partnera", cs_CZ="Technická událost: Kontaktujte partnera Audi", da_DK="En teknisk hændelse: Kontakt Audi partner", de_DE="Ein technisches Ereignis: Audi Partner kontaktieren", el_GR="Ένα τεχνικό συμβάν: Επικοινωνήστε με εξουσιοδοτημένο συνεργάτη Audi", en_GB="One technical event: contact Audi Partner", es_ES="Una incidencia técnica: Contactar con Concesionario Audi", fi_FI="Tekninen tapahtuma: ota yhteyttä Audi-jälleenmyyjään", fr_FR="Un événement technique: contactez un Partenaire Audi", hr_HR="Tehnički događaj: kontaktirati s Audi partnerom", hu_HU="Egy műszaki esemény: vedd fel a kapcsolatot egy Audi partnerrel", it_IT="Un evento di natura tecnica: contattare il partner Audi", nl_NL="Een technische gebeurtenis: neem contact op met de Audi-partner", no_NO="En teknisk hendelse: Kontakt Audi-verkstedet", pl_PL="Zdarzenie techniczne: zgłoś się do dealera Audi", pt_PT="Uma ocorrência técnica: contactar Concessionário Audi", ro_RO="Un eveniment tehnic: contactaţi partenerul Audi", ru_RU="Техническое событие: обратитесь к своему партнеру Audi", sk_SK="Technická udalosť: kontaktujte partnera Audi", sl_SI="Tehnični dogodek: obrnite se na pooblaščenega partnerja Audi", sr_RS="Tehnički rezultat: Stupiti u kontakt sa Audi partnerom", sv_SE="En teknisk händelse: Kontakta en Audi-partner", tr_TR="Teknik bir olay: Audi yetkili servis ile iletişime geçin", uk_UA="Технічна подія: зверніться до партнера Audi")
rd_yellow_singleWarning_title_short = TextObject(bs_BA="Tehnički događaj", cs_CZ="Technická akce", da_DK="En teknisk hændelse", de_DE="Ein technisches Ereignis", el_GR="Ένα τεχνικό συμβάν", en_GB="One technical event", es_ES="Una incidencia técnica", fi_FI="Tekninen tapahtuma", fr_FR="Un événement technique", hr_HR="Tehnički događaj", hu_HU="Egy műszaki esemény", it_IT="Un evento di natura tecnica", nl_NL="Een technische gebeurtenis", no_NO="En teknisk hendelse", pl_PL="Zdarzenie techniczne", pt_PT="Uma ocorrência técnica", ro_RO="Un eveniment tehnic", ru_RU="Техническое событие", sk_SK="Technická udalosť", sl_SI="Tehnični dogodek", sr_RS="Tehnički rezultat", sv_SE="En teknisk händelse", tr_TR="Teknik bir olay", uk_UA="Технічна подія")
rd_yellow_warning_disclaimer_textbox = TextObject(bs_BA="U Vašem vozilu su prepoznati tehnički događaji. Potrebno je da Audi partner što prije provjeri dijagnosticirano\nodstupanje.", cs_CZ="Ve vašem vozidle byly zjištěny technické události. Nechte prosím diagnostikovanou abnormalitu co nejdříve\nzkontrolovat u partnera Audi.", da_DK="Der blev registreret tekniske hændelser i din bil. Få den diagnosticerede hændelse kontrolleret af en Audi partner\ninden for kort tid.", de_DE="In deinem Fahrzeug wurden technische Ereignisse erkannt. Bitte lasse die diagnostizierte Auffälligkeit zeitnah von\nAudi Partner überprüfen.", el_GR="Στο όχημά σας αναγνωρίστηκαν τεχνικά συμβάντα. Αναθέστε σύντομα σε εξουσιοδοτημένο συνεργάτη Audi τον έλεγχο\nτου ασυνήθιστου ευρήματος που διαγνώστηκε.", en_GB="Technical events have been detected in your vehicle. Please have the diagnosed issue checked promptly by your\nAudi Partner.", es_ES="Se han detectado incidencias técnicas en su vehículo. Por favor, póngase en contacto con su Concesionario Audi lo\nantes posible para que comprueben las incidencias diagnosticadas.", fi_FI="Autossasi tunnistettiin teknisiä tapahtumia. Anna Audi-jälleenmyyjän tarkastaa diagnosoitu häiriö pian.", fr_FR="Des événements techniques ont été détectés dans votre véhicule. Veuillez faire contrôler dès que possible\nl'anomalie diagnostiquée par un Partenaire Audi.", hr_HR="U vašem vozilu su prepoznati tehnički događaji. Dajte dijagnosticirano odstupanje što prije provjeriti kod Audi\npartnera.", hu_HU="Műszaki események vannak felismerve a járművedben. Kérünk, a diagnosztizált rendellenességet mielőbb\nellenőriztesd egy Audi partnerrel.", it_IT="Sono stati rilevati degli eventi di natura tecnica sulla vettura. Far controllare al più presto da un partner Audi\nl'anomalia diagnosticata.", nl_NL="Er zijn technische gebeurtenissen gedetecteerd in je voertuig. Laat de gediagnosticeerde afwijking zo snel mogelijk\ndoor je Audi-partner controleren.", no_NO="Det er registrert tekniske hendelser i bilen. Få dette kontrollert på et Audi-verksted snart.", pl_PL="W pojeździe wykryto zdarzenia techniczne. Zleć jak najszybciej sprawdzenie zdiagnozowanej nieprawidłowości\ndealerowi Audi.", pt_PT="Foram reconhecidas ocorrências técnicas no teu veículo. Desloca-te ao Concessionário Audi com brevidade para\nverificação do problemas diagnosticado.", ro_RO="În autovehiculul dumneavoastră au fost recunoscute evenimente tehnice. Solicitaţi verificarea problemei\ndiagnosticate de către partenerul Audi.", ru_RU="В вашем автомобиле обнаружены технические события. Пожалуйста, как можно скорее проверьте\nдиагностированную аномалию у партнера Audi.", sk_SK="Vo vašom vozidle boli zistené technické udalosti. Diagnostikovanú anomáliu nechajte čo najskôr skontrolovať u\npartnera Audi.", sl_SI="Sistem je v vašem vozilu zaznal tehnične dogodke. Diagnosticirano nepravilnost naj pravočasno preverijo pri\npooblaščenem partnerju Audi.", sr_RS="U vašem vozilu su detektovani tehnički događaji. Neka utvrđenu nedoslednost što pre proveri Audi partner.", sv_SE="Tekniska händelser har upptäckts i din bil. Låt en Audi-partner kontrollera den diagnostiserade avvikelsen så snart\nsom möjligt.", tr_TR="Aracında teknik olaylar algılandı. Lütfen teşhis edilen anormalliği mümkün olan en kısa sürede Audi yetkili\nservisinde kontrol ettir.", uk_UA="У вашому автомобілі виявлено технічні події. Будь ласка, якнайшвидше зверніться до партнера Audi для\nперевірки виявленої аномалії.")
rd_yellow_warning_title = TextObject(bs_BA="%1 tehničkih događaja: Stupiti u kontakt s Audi partnerom", cs_CZ="%1 technické události: Kontaktujte partnera Audi", da_DK="%1 tekniske hændelser: Kontakt Audi partner", de_DE="%1 technische Ereignisse: Audi Partner kontaktieren", el_GR="%1 τεχνικά συμβάντα: Επικοινωνήστε με εξουσιοδοτημένο συνεργάτη Audi", en_GB="%1 technical events: contact Audi Partner", es_ES="%1 incidencias técnicas: Contactar con Concesionario Audi", fi_FI="Teknisiä tapahtumia on %1: ota yhteyttä Audi-jälleenmyyjään", fr_FR="%1 événements techniques: contactez un Partenaire Audi", hr_HR="Tehničkih događaja - %1: kontaktirati s Audi partnerom", hu_HU="%1 műszaki esemény: vedd fel a kapcsolatot egy Audi partnerrel", it_IT="%1 eventi di natura tecnica: contattare il partner Audi", nl_NL="%1 technische gebeurtenissen: neem contact op met de Audi-partner", no_NO="%1 tekniske hendelser: Kontakt Audi-verkstedet", pl_PL="%1 zdarzenia techniczne: zgłoś się do dealera Audi", pt_PT="%1 ocorrências técnicas: contactar Concessionário Audi", ro_RO="%1 evenimente tehnice: contactaţi partenerul Audi", ru_RU="%1 технических событий: свяжитесь с партнером Audi", sk_SK="%1 technických udalostí: kontaktujte partnera Audi", sl_SI="Tehnični dogodki (%1): obrnite se na pooblaščenega partnerja Audi", sr_RS="%1 tehničkih događaja: Kontaktirati Audi partnera", sv_SE="%1 tekniska händelser: Kontakta en Audi-partner", tr_TR="%1 teknik olay: Audi yetkili servis ile iletişime geçin", uk_UA="%1 технічних подій: зверніться до партнера Audi")
rd_yellow_warning_title_short = TextObject(bs_BA="%1 tehničkih događaja", cs_CZ="%1 technických událostí", da_DK="%1 tekniske hændelser", de_DE="%1 technische Ereignisse", el_GR="%1 τεχνικά συμβάντα", en_GB="%1 technical events", es_ES="%1 incidencias técnicas", fi_FI="Teknisiä tapahtumia on %1", fr_FR="%1 événements techniques", hr_HR="Tehničkih događaja: %1", hu_HU="%1 műszaki esemény", it_IT="%1 eventi di natura tecnica", nl_NL="%1 technische gebeurtenissen", no_NO="%1 tekniske hendelser", pl_PL="%1 zdarzenia techniczne", pt_PT="%1 ocorrência técnica", ro_RO="%1 evenimente tehnice", ru_RU="%1 технических событий", sk_SK="%1 technické udalosti", sl_SI="Tehnični dogodki: %1", sr_RS="%1 tehničkih događaja", sv_SE="%1 tekniska händelser", tr_TR="%1 teknik olay", uk_UA="%1 технічних подій")
rdkBatteryLF_modId8_critText_crit0 = TextObject(bs_BA="Trenutno nema raspoloživih podataka iz vozila. Iz tog razloga nije moguće staviti na raspolaganje blagovremene informacije o predstojećoj potrebi servisiranja.", cs_CZ="V současné době nejsou k dispozici žádné údaje o vozidle. To znamená, že nelze poskytnout žádné včasné informace o nadcházejícím požadavku na servisní službu.", da_DK="Der er p.t. ingen tilgængelige data fra bilen. Der kan således ikke stilles nogen tidlige informationer om forestående servicebehov til rådighed.", de_DE="Zurzeit sind keine Daten aus dem Fahrzeug verfügbar. Somit können noch keine frühzeitigen Informationen über einen anstehenden Servicebedarf zur Verfügung gestellt werden.", el_GR="Προς το παρόν δεν υπάρχουν διαθέσιμα δεδομένα από το όχημα. Συνεπώς δεν μπορούν ακόμη να διατεθούν πληροφορίες σχετικά με μια επικείμενη ανάγκη για Service.", en_GB="No data currently available from vehicle. This means that no advance information can yet be provided about upcoming service requirements.", es_ES="Actualmente no hay datos del vehículo disponibles. Por consiguiente, todavía no se puede adelantar información sobre intervenciones de mantenimiento pendientes.", fi_FI="Tällä hetkellä tietoja autosta ei ole käytettävissä. Siksi ennakkotietoja tulevasta huoltotarpeesta ei vielä pystytä antamaan.", fr_FR="Aucune donnée du véhicule n'est disponible actuellement. Par conséquent, il n'est pas encore possible de fournir des informations en temps voulu sur une opération d'entretien à venir.", hr_HR="Trenutačno nema raspoloživih podataka iz vozila. Zbog toga još nije moguće na raspolaganje staviti podatke o potrebnim servisima.", hu_HU="Jelenleg nem állnak rendelkezésre adatok a járműből. Emiatt egyelőre nem lehet korábbi tájékoztatást adni egy közelgő szükséges szervizről.", it_IT="Al momento non sono disponibili dati della vettura. Quindi non è ancora possibile fornire informazioni tempestive sulla prossima manutenzione necessaria.", nl_NL="Er zijn momenteel geen gegevens van het voertuig beschikbaar. Dit betekent dat er geen vroegtijdige informatie over een komende onderhoudsbeurt kan worden opgegeven.", no_NO="Ingen data fra bilen er tilgjengelige for øyeblikket. Derfor kan du ikke varsles på forhånd om kommende servicebehov.", pl_PL="Obecnie nie są dostępne żadne dane z pojazdu. Dlatego nie jest jeszcze możliwe udostępnienie żadnych wcześniejszych informacji o zbliżających się wymaganiach serwisowych.", pt_PT="Atualmente não existem dados disponíveis no veículo. Por isso, ainda não podem ser atempadamente disponibilizadas informações sobre o serviço pendente.", ro_RO="Momentan nu sunt disponibile date din autovehicul. Astfel nu pot fi puse la dispoziţie informaţii timpurii cu privire la o necesitate de service scadentă.", ru_RU="В настоящее время данные с автомобиля отсутствуют. Это означает, что пока невозможно предоставить заблаговременную информацию о предстоящем обслуживании.", sk_SK="Momentálne nie sú k dispozícii žiadne údaje z vozidla. To znamená, že zatiaľ nie je možné poskytnúť žiadne včasné informácie o nadchádzajúcej požiadavke na servis.", sl_SI="Podatki iz vozila trenutno niso na voljo. Tako ni mogoče posredovati pravočasnih informacij o potrebnih servisnih storitvah.", sr_RS="Trenutno nema dostupnih podataka iz vozila. Iz tog razloga još uvek ne mogu da se stave na raspolaganje informacije o predstojećoj servisnoj potrebi.", sv_SE="Det finns inga data tillgängliga från bilen just nu. Därför kan ingen information om kommande servicebehov visas.", tr_TR="Şu anda araçla ilgili hiçbir veri mevcut değil. Dolayısıyla, henüz yaklaşmakta olan bir servis gereksinimi hakkında erken bir bilgi verilemiyor.", uk_UA="Наразі немає жодних даних з автомобілю. Це означає, що поки що неможливо надати будь-яку попередню інформацію про майбутню необхідність техобслуговування.")
rdkBatteryLF_modId8_critText_crit1 = TextObject(de_DE="Damit der Reifendrucksensor zuverlässig bei einem Reifendruckverlust warnen kann, muss die Batterie der Reifendruckkontrolle bei Bedarf ausgetauscht werden. Du wirst frühzeitig informiert, wenn ein Service notwendig ist.")
rdkBatteryLF_modId8_critText_crit2 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle wurde länger nicht ausgetauscht. Vereinbare einen Termin zur Prüfung bei deinem Audi Partner, damit der Reifendruck weiter zuverlässig überwacht werden kann.")
rdkBatteryLF_modId8_critText_crit4 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle wurde länger nicht ausgetauscht. Damit der Reifendruck weiter zuverlässig überwacht werden kann, lasse diese bitte bei deinem Audi Partner überprüfen.")
rdkBatteryLF_modId8_modelDes = TextObject(de_DE="Die Reifendrucksensoren überwachen regelmäßig den Reifendruck deines Fahrzeugs, um dich bei einem Druckverlust zu warnen. Dieser Messwert wird über Funk an dein Fahrzeug übertragen. Zur Sicherstellung der Messung muss bei Bedarf der Sensor inklusive der Batterie ausgetauscht werden.")
rdkBatteryLF_modId8_modelName = TextObject(de_DE="Batterie für die Reifendruckkontrolle (vorne links)")
rdkBatteryLF_modId8_servicePartnerText_crit0 = TextObject(de_DE="Du könntest demnächst die Batterie für die Reifendruckkontrolle (vorne links) prüfen lassen.")
rdkBatteryLF_modId8_servicePartnerText_crit1 = TextObject(de_DE="Du könntest demnächst die Batterie für die Reifendruckkontrolle (vorne links) prüfen lassen.")
rdkBatteryLF_modId8_servicePartnerText_crit2 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle (vorne links) muss überprüft werden.")
rdkBatteryLF_modId8_servicePartnerText_crit4 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle (vorne links) muss überprüft und vermutlich gewechselt werden.")
rdkBatteryLF_modId8_shortDes_crit1 = TextObject(bs_BA="Trenutno nema poruka.", cs_CZ="Momentálně nejsou žádné zprávy.", da_DK="Ingen meddelelser p.t.", de_DE="Zurzeit gibt es keine Meldungen.", el_GR="Προς το παρόν δεν υπάρχουν μηνύματα.", en_GB="There are currently no notifications.", es_ES="No hay mensajes actualmente.", fi_FI="Ilmoituksia ei tällä hetkellä ole.", fr_FR="Aucun message actuellement.", hr_HR="Trenutačno nema obavijesti.", hu_HU="Jelenleg nincs üzenet.", it_IT="Al momento non ci sono messaggi.", nl_NL="Er zijn momenteel geen meldingen.", no_NO="Du har ingen meldinger nå.", pl_PL="Obecnie brak komunikatów.", pt_PT="De momento não existem indicações.", ro_RO="Momentan nu există mesaje.", ru_RU="В настоящее время нет сообщений.", sk_SK="Momentálne nie sú žiadne hlásenia.", sl_SI="Trenutno ni nobenih obvestil.", sr_RS="Trenutno nema poruka.", sv_SE="Det finns inga meddelanden just nu.", tr_TR="Şu anda herhangi bir bildirim yok.", uk_UA="Наразі немає жодних повідомлень.")
rdkBatteryLF_modId8_shortDes_crit2 = TextObject(de_DE="Batterie für die Reifendruckkontrolle (vorne links) bald überprüfen")
rdkBatteryLF_modId8_shortDes_crit4 = TextObject(de_DE="Batterie für die Reifendruckkontrolle (vorne links) jetzt überprüfen")
rdkBatteryLR_modId10_critText_crit0 = TextObject(bs_BA="Trenutno nema raspoloživih podataka iz vozila. Iz tog razloga nije moguće staviti na raspolaganje blagovremene informacije o predstojećoj potrebi servisiranja.", cs_CZ="V současné době nejsou k dispozici žádné údaje o vozidle. To znamená, že nelze poskytnout žádné včasné informace o nadcházejícím požadavku na servisní službu.", da_DK="Der er p.t. ingen tilgængelige data fra bilen. Der kan således ikke stilles nogen tidlige informationer om forestående servicebehov til rådighed.", de_DE="Zurzeit sind keine Daten aus dem Fahrzeug verfügbar. Somit können noch keine frühzeitigen Informationen über einen anstehenden Servicebedarf zur Verfügung gestellt werden.", el_GR="Προς το παρόν δεν υπάρχουν διαθέσιμα δεδομένα από το όχημα. Συνεπώς δεν μπορούν ακόμη να διατεθούν πληροφορίες σχετικά με μια επικείμενη ανάγκη για Service.", en_GB="No data currently available from vehicle. This means that no advance information can yet be provided about upcoming service requirements.", es_ES="Actualmente no hay datos del vehículo disponibles. Por consiguiente, todavía no se puede adelantar información sobre intervenciones de mantenimiento pendientes.", fi_FI="Tällä hetkellä tietoja autosta ei ole käytettävissä. Siksi ennakkotietoja tulevasta huoltotarpeesta ei vielä pystytä antamaan.", fr_FR="Aucune donnée du véhicule n'est disponible actuellement. Par conséquent, il n'est pas encore possible de fournir des informations en temps voulu sur une opération d'entretien à venir.", hr_HR="Trenutačno nema raspoloživih podataka iz vozila. Zbog toga još nije moguće na raspolaganje staviti podatke o potrebnim servisima.", hu_HU="Jelenleg nem állnak rendelkezésre adatok a járműből. Emiatt egyelőre nem lehet korábbi tájékoztatást adni egy közelgő szükséges szervizről.", it_IT="Al momento non sono disponibili dati della vettura. Quindi non è ancora possibile fornire informazioni tempestive sulla prossima manutenzione necessaria.", nl_NL="Er zijn momenteel geen gegevens van het voertuig beschikbaar. Dit betekent dat er geen vroegtijdige informatie over een komende onderhoudsbeurt kan worden opgegeven.", no_NO="Ingen data fra bilen er tilgjengelige for øyeblikket. Derfor kan du ikke varsles på forhånd om kommende servicebehov.", pl_PL="Obecnie nie są dostępne żadne dane z pojazdu. Dlatego nie jest jeszcze możliwe udostępnienie żadnych wcześniejszych informacji o zbliżających się wymaganiach serwisowych.", pt_PT="Atualmente não existem dados disponíveis no veículo. Por isso, ainda não podem ser atempadamente disponibilizadas informações sobre o serviço pendente.", ro_RO="Momentan nu sunt disponibile date din autovehicul. Astfel nu pot fi puse la dispoziţie informaţii timpurii cu privire la o necesitate de service scadentă.", ru_RU="В настоящее время данные с автомобиля отсутствуют. Это означает, что пока невозможно предоставить заблаговременную информацию о предстоящем обслуживании.", sk_SK="Momentálne nie sú k dispozícii žiadne údaje z vozidla. To znamená, že zatiaľ nie je možné poskytnúť žiadne včasné informácie o nadchádzajúcej požiadavke na servis.", sl_SI="Podatki iz vozila trenutno niso na voljo. Tako ni mogoče posredovati pravočasnih informacij o potrebnih servisnih storitvah.", sr_RS="Trenutno nema dostupnih podataka iz vozila. Iz tog razloga još uvek ne mogu da se stave na raspolaganje informacije o predstojećoj servisnoj potrebi.", sv_SE="Det finns inga data tillgängliga från bilen just nu. Därför kan ingen information om kommande servicebehov visas.", tr_TR="Şu anda araçla ilgili hiçbir veri mevcut değil. Dolayısıyla, henüz yaklaşmakta olan bir servis gereksinimi hakkında erken bir bilgi verilemiyor.", uk_UA="Наразі немає жодних даних з автомобілю. Це означає, що поки що неможливо надати будь-яку попередню інформацію про майбутню необхідність техобслуговування.")
rdkBatteryLR_modId10_critText_crit1 = TextObject(de_DE="Damit der Reifendrucksensor zuverlässig bei einem Reifendruckverlust warnen kann, muss die Batterie der Reifendruckkontrolle bei Bedarf ausgetauscht werden. Du wirst frühzeitig informiert, wenn ein Service notwendig ist.")
rdkBatteryLR_modId10_critText_crit2 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle wurde länger nicht ausgetauscht. Vereinbare einen Termin zur Prüfung bei deinem Audi Partner, damit der Reifendruck weiter zuverlässig überwacht werden kann.")
rdkBatteryLR_modId10_critText_crit4 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle wurde länger nicht ausgetauscht. Damit der Reifendruck weiter zuverlässig überwacht werden kann, lasse diese bitte bei deinem Audi Partner überprüfen.")
rdkBatteryLR_modId10_modelDes = TextObject(de_DE="Die Reifendrucksensoren überwachen regelmäßig den Reifendruck deines Fahrzeugs, um dich bei einem Druckverlust zu warnen. Dieser Messwert wird über Funk an dein Fahrzeug übertragen. Zur Sicherstellung der Messung muss bei Bedarf der Sensor inklusive der Batterie ausgetauscht werden.")
rdkBatteryLR_modId10_modelName = TextObject(de_DE="Batterie für die Reifendruckkontrolle (hinten links)")
rdkBatteryLR_modId10_servicePartnerText_crit0 = TextObject(de_DE="Du könntest demnächst die Batterie für die Reifendruckkontrolle (hinten links) prüfen lassen.")
rdkBatteryLR_modId10_servicePartnerText_crit1 = TextObject(de_DE="Du könntest demnächst die Batterie für die Reifendruckkontrolle (hinten links) prüfen lassen.")
rdkBatteryLR_modId10_servicePartnerText_crit2 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle (hinten links) muss überprüft werden.")
rdkBatteryLR_modId10_servicePartnerText_crit4 = TextObject(de_DE="Die Batterie für die Reifendruckkontrolle (hinten links) muss überprüft und vermutlich gewechselt werden.")
rdkBatteryLR_modId10_shortDes_crit1 = TextObject(bs_BA="Trenutno nema poruka.", cs_CZ="Momentálně nejsou žádné zprávy.", da_DK="Ingen meddelelser p.t.", de_DE="Zurzeit gibt es keine Meldungen.", el_GR="Προς το παρόν δεν υπάρχουν μηνύματα.", en_GB="There are currently no notifications.", es_ES="No hay mensajes actualmente.", fi_FI="Ilmoituksia ei tällä hetkellä ole.", fr_FR="Aucun message actuellement.", hr_HR="Trenutačno nema obavijesti.", hu_HU="Jelenleg nincs üzenet.", it_IT="Al momento non ci sono messaggi.", nl_NL="Er zijn momenteel geen meldingen.", no_NO="Du har ingen meldinger nå.", pl_PL="Obecnie brak komunikatów.", pt_PT="De momento não existem indicações.", ro_RO="Momentan nu există mesaje.", ru_RU="В настоящее время нет сообщений.", sk_SK="Momentálne nie sú žiadne hlásenia.", sl_SI="Trenutno ni nobenih obvestil.", sr_RS="Trenutno nema poruka.", sv_SE="Det finns inga meddelanden just nu.", tr_TR="Şu anda herhangi bir bildirim yok.", uk_UA="Наразі немає жодних повідомлень.")
rdkBatteryLR_modId10_shortDes_crit2 = TextObject(de_DE="Batterie für die Reifendruckkontrolle (hinten links) bald überprüfen")
rdkBatteryLR_modId10_shortDes_crit4 = TextObject(de_DE="Batterie für die Reifendruckkontrolle (hinten links) jetzt überprüfen")
