remoteDiagnosis_info_details = TextObject(bs_BA="Aktivirajte ovu uslugu za\nautomatsko primanje informacija\no porukama relevantnim za\nservisiranje.", cs_CZ="Aktivujte tuto službu, abyste\nautomaticky dostávali informace\no zprávách důležitých pro servis.", da_DK="Aktiver denne service for\nautomatisk at modtage\ninformation om servicerelevante\nmeddelelser.", de_DE="Aktiviere diesen Service, um\nautomatisch Informationen zu\nservicerelevanten Meldungen zu\nerhalten.", el_GR="Ενεργοποιήστε αυτήν την\nυπηρεσία, για να λαμβάνετε\nαυτομάτως πληροφορίες για\nμηνύματα σχετικά με Service.", en_GB="Activate this service to\nautomatically receive\ninformation about\nservice-related notifications.", es_ES="Activar este servicio para recibir\nautomáticamente información\nsobre mensajes relativos al\nServicio.", fi_FI="Aktivoi tämä palvelu, jotta saat\nautomaattisesti tietoja huoltoon\nliittyvistä ilmoituksista.", fr_FR="Activez ce service pour obtenir\nautomatiquement des\ninformations concernant les\nmessages relatifs à l'entretien.", hr_HR="Aktivirajte ovaj servis kako biste\nautomatski primali informacije o\nobavijestima bitnim za servis.", hu_HU="Ha automatikus tájékoztatást\nszeretnél a szervizzel kapcsolatos\nüzenetekről, aktiváld ezt a\nszolgáltatást.", it_IT="Attivare questo sevizio per\nricevere automaticamente\ninformazioni sui messaggi\nrilevanti per il service.", nl_NL="Activeer deze service om\nautomatisch informatie te\nontvangen over servicerelevante\nberichten.", no_NO="Aktiver denne tjenesten for å få\nautomatisk informasjon om\nservicerelaterte meldinger.", pl_PL="Aktywuj tę usługę, aby\nautomatycznie otrzymywać\ninformacje o komunikatach\nzwiązanych z serwisem.", pt_PT="Ativa este serviço para receberes\ninformações automáticas para\navisos relevantes de serviço.", ro_RO="Activaţi acest serviciu, pentru a\nprimi automat informaţii despre\nmesaje relevante pentru service.", ru_RU="Активируйте этот сервис, чтобы\nавтоматически получать\nинформацию о сообщениях,\nимеющих отношение к\nобслуживанию.", sk_SK="Aktivujte túto službu, aby ste\nautomaticky získavali informácie\no hláseniach vzťahujúcich sa na\nservis.", sl_SI="Za avtomatsko prejemanje\ninformacij o obvestilih,\npomembnih za servis, aktivirajte\nto storitev.", sr_RS="Aktivirajte ovu uslugu za\nautomatsko primanje informacija o\nporukama relevantnim za servis.", sv_SE="Aktivera denna tjänst för att\nautomatiskt få information om\nservicerelaterade meddelanden.", tr_TR="Servis ile ilgili bildirimler\nhakkında otomatik olarak bilgi\nalmak için bu hizmeti etkinleştir.", uk_UA="Активуйте цей сервіс, щоб\nавтоматично отримувати\nінформацію про повідомлення,\nпов'язані з сервісом.")
remoteDiagnosis_setup_title = TextObject(bs_BA="Automatsko izvođenje daljinske dijagnoze vozila u pozadini", cs_CZ="Automatické provádění dálkové diagnostiky vozidla na pozadí", da_DK="Automatisk gennemførelse af bilfjerndiagnose i baggrunden", de_DE="Automatische Durchführung der Fahrzeug-Ferndiagnose im Hintergrund", el_GR="Αυτόματη εκτέλεση της απομακρυσμένης διάγνωσης οχήματος στο παρασκήνιο", en_GB="Remote vehicle diagnostics automatically performed in the background", es_ES="Ejecución automática en segundo plano de la diagnosis remota del vehículo", fi_FI="Auton etädiagnoosin suorittaminen automaattisesti taustalla", fr_FR="Exécution automatique du diagnostic à distance du véhicule en arrière-plan", hr_HR="Automatska provedba dijagnoze vozila na daljinu u pozadini", hu_HU="Jármű-távdiagnosztika automatikus végrehajtása a háttérben", it_IT="Esecuzione automatica in sottofondo della diagnosi vettura a distanza", nl_NL="Automatisch uitvoeren van voertuigdiagnose op afstand op de achtergrond", no_NO="Utfør fjerndiagnose av bilen automatisk i bakgrunnen", pl_PL="Automatyczne realizowanie zdalnej diagnostyki pojazdu w tle", pt_PT="Realização automática do diagnóstico remoto do veículo em segundo plano", ro_RO="Executare automată a telediagnozei autovehiculului în fundal", ru_RU="Автоматическое выполнение удаленной диагностики а/м в фоновом режиме", sk_SK="Automatické uskutočnenie diaľkovej diagnostiky vozidla na pozadí", sl_SI="Avtomatska izvedba telediagnoze vozila v ozadju", sr_RS="Automatsko provođenje daljinske dijagnostike vozila u pozadini", sv_SE="Automatisk fjärrdiagnos av bilen i bakgrunden", tr_TR="Arka planda araç uzaktan teşhisinin otomatik olarak uygulanması", uk_UA="Автоматичне виконання дистанційної діагностики а/м у фоновому режимі")
