search_ServiceRequest_details = TextObject(bs_BA="Pregled svih upita i termina za servisiranje", cs_CZ="Přehled všech servisních požadavků a schůzek", da_DK="Overblik over alle serviceforespørgsler og -aftaler", de_DE="Überblick aller Serviceanfragen und -termine", el_GR="Επισκόπηση όλων των αιτημάτων και ραντεβού για Service", en_GB="Overview of all service requests and appointments", es_ES="Resumen de todas las consultas y citas de Servicio", fi_FI="Yhteenveto kaikista huoltopyynnöistä ja ajanvarauksista", fr_FR="Vue d'ensemble de toutes les demandes d'entretien et de tous les rendez-vous d'entretien", hr_HR="Pregled svih upita i termina za servis", hu_HU="Összes szervizigénylés és -időpont áttekintése", it_IT="Panoramica di tutte le richieste di assistenza e gli appuntamenti per il service", nl_NL="Overzicht van alle serviceaanvragen en -afspraken", no_NO="Oversikt over alle serviceforespørsler og servicetimer", pl_PL="Przegląd wszystkich zapytań i terminów serwisowych", pt_PT="Apresentação de todos os pedidos e marcações de serviço", ro_RO="Prezentare generală a tuturor solicitărilor şi programărilor de service", ru_RU="Обзор всех запросов и сроков техобслуживания", sk_SK="Prehľad všetkých požiadaviek a termínov servisu", sl_SI="Pregled vseh servisnih zahtev in terminov", sr_RS="Pregled svih zahteva i termina za servis", sv_SE="Översikt över alla serviceförfrågningar och tidsbokningar", tr_TR="Tüm servis taleplerine ve randevulara genel bakış", uk_UA="Огляд усіх запитів та строків сервісу")
