serviceStatus_requestSent_dialog = TextObject(bs_BA="Vaš upit je proslijeđen Audi partneru. On će blagovremeno\nstupiti u kontakt s Vama.", cs_CZ="Váš požadavek byl předán vašemu Audi partnerovi. Budou\nvás kontaktovat co nejdříve.", da_DK="Din forespørgsel blev videresendt til din Audi partner.\nDenne vil snart kontakte dig.", de_DE="Deine Anfrage wurde an deinen Audi Partner weitergeleitet.\nDieser wird sich zeitnah mit dir in Verbindung setzen.", el_GR="Το αίτημά σας μεταβιβ.στ.εξουσ.συνεργ.Audi π.σ.εξυπηρ.\nΑυτός θα επικοινωνήσει σύντομα μαζί σας.", en_GB="Your request has been forwarded to your Audi Partner. They\nwill contact you promptly.", es_ES="La consulta se ha reenviado a su Concesionario Audi. Se\npondrán en contacto con usted lo antes posible.", fi_FI="Pyyntösi on välitetty Audi-jälleenmyyjälle. Sieltä otetaan\nsinuun pian yhteyttä.", fr_FR="Votre demande a été transférée à votre Partenaire Audi. Ce\ndernier vous contactera dans les plus brefs délais.", hr_HR="Vaš je upit proslijeđen vašem Audi partneru. On će ubrzo\nstupiti u kontakt s vama.", hu_HU="Kérésedet továbbítottuk Audi partneredhez, aki hamarosan\nkapcsolatban lép veled.", it_IT="La Sua richiesta è stata inoltrata al Suo partner Audi, che la\ncontatterà al più presto.", nl_NL="Jouw aanvraag is doorgestuurd naar je Audi-partner. Zij\nzullen zo snel mogelijk contact met je opnemen.", no_NO="Forespørselen videresendes til Audi-verkstedet ditt.\nVerkstedet vil snart ta kontakt med deg.", pl_PL="Twoje zapytanie zostało przekazane do dealera Audi.\nSkontaktuje się on z Tobą wkrótce.", pt_PT="O teu pedido foi reencaminhado para o teu Concessionário\nAudi. Este entrará em contacto contigo em breve.", ro_RO="Solicitarea a fost transmisă către partenerul\ndumneavoastră Audi. Acesta vă va contacta cât mai curând.", ru_RU="Ваш запрос был передан партнеру Audi. Он свяжется с\nвами как можно скорее.", sk_SK="Vaša požiadavka bola postúpená vášmu partnerovi Audi.\nTento sa s vami spojí čo najskôr.", sl_SI="Vaša zahteva je bila posredovana partnerju Audi.\nTa bo v najkrajšem možnem času vzpostavil stik z vami.", sr_RS="Vaš zahtev je prosleđen Audi partneru. Isti će uskoro stupiti\nsa vama u kontakt.", sv_SE="Din förfrågan har vidarebefordrats till din Audi-partner.\nPartnern kommer att kontakta dig inom kort.", tr_TR="Talebin Audi yetkili servisine iletildi. En kısa zamanda seninle\niletişime geçecektir.", uk_UA="Ваш запит було передано партнеру Audi. Він зв'яжеться з\nвами найближчим часом.")
service_activation_action = TextObject(bs_BA="Na aktiviranje usluge", cs_CZ="Pro aktivaci služby", da_DK="Til tjenesteaktivering", de_DE="Zur Dienstaktivierung", el_GR="Μετάβαση στην ενεργοποίηση υπηρεσίας", en_GB="Go to activation of service", es_ES="A la activación del servicio", fi_FI="Siirry palvelun aktivointiin", fr_FR="Accéder à l'activation du service", hr_HR="Na aktiviranje usluge", hu_HU="A szolgáltatás aktiválásához", it_IT="Vai all'attivazione del servizio", nl_NL="Voor serviceactivering", no_NO="Til aktivering av tjenesten", pl_PL="Do aktywacji usługi", pt_PT="Sobre ativação do serviço", ro_RO="Spre activarea serviciului", ru_RU="Для активации сервиса", sk_SK="O aktivácii služby", sl_SI="Na aktivacijo storitve", sr_RS="Na deaktiviranje usluge", sv_SE="Till aktivering av tjänsten", tr_TR="Hizmet aktivasyonuna git", uk_UA="Для активації служби")
service_deactivation_action = TextObject(bs_BA="Deaktiviraj", cs_CZ="Deaktivovat", da_DK="Deaktiver", de_DE="Deaktivieren", el_GR="Απενεργοποίηση", en_GB="Deactivate", es_ES="Desactivar", fi_FI="Deaktivoi", fr_FR="Désactiver", hr_HR="Deaktivirati", hu_HU="Deaktiválás", it_IT="Disattiva", nl_NL="Deactiveren", no_NO="Deaktiver", pl_PL="Dezaktywuj", pt_PT="Desativar", ro_RO="Dezactivare", ru_RU="Отключить", sk_SK="Deaktivovať", sl_SI="Deaktiviranje", sr_RS="Deaktiviranje", sv_SE="Avaktivera", tr_TR="Devre dışı bırak", uk_UA="Вимкнути")
service_deactivation_dialog = TextObject(bs_BA="Više se ne vrši razmjena podataka o vozilu s vašim Audi partnerom\ni on Vas više neće automatski kontaktirati u slučaju servisiranja.", cs_CZ="Údaje o vozidle již nebudou sdíleny s vaším partnerem Audi a v\npřípadě servisu vás již nebudou automaticky kontaktovat.", da_DK="Der deles ikke længere bildata med din Audi partner, og denne vil\nikke længere automatisk kontakte dig i forbindelse med service.", de_DE="Es werden keine Fahrzeugdaten mehr mit deinem Audi Partner\ngeteilt und er wird dich nicht mehr automatisch im Servicefall\nkontaktieren.", el_GR="Δεν κοινοποιούνται πλέον στοιχεία του οχήματος με τον\nεξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί, και δεν θα\nεπικοινωνήσει αυτομάτως μαζί σας για Service.", en_GB="Vehicle data will no longer be shared with your Audi Partner and\nthey will no longer contact you automatically for services.", es_ES="Ya no se compartirán los datos del vehículo con su Concesionario\nAudi; su Concesionario Audi ya no se pondrá en contacto con usted\nautomáticamente en caso de necesidades de Servicio.", fi_FI="Auton tietoja ei enää välitetä Audi-jälleenmyyjälle, eikä sieltä enää\noteta automaattisesti yhteyttä huoltoa varten.", fr_FR="Les données du véhicule ne sont plus partagées avec votre\nPartenaire Audi et ce dernier ne vous contactera plus\nautomatiquement dans le cadre d'un entretien.", hr_HR="Više ne dijelite podatke o vozilu sa svojim Audi partnerom i on u\nslučaju servisa više neće automatski kontaktirati s vama.", hu_HU="A továbbiakban nem adjuk át a járműadatokat Audi partnerednek,\nés szerviz esetén nem vesszük fel veled automatikusan a\nkapcsolatot.", it_IT="I dati della vettura non saranno più condivisi con il partner Audi,\nche non La contatterà più automaticamente per la manutenzione.", nl_NL="Voertuiggegevens worden niet langer gedeeld met je Audi-partner\nen zij nemen niet langer automatisch contact met je op bij een\nserviceaanvraag.", no_NO="Ingen bildata deles heretter med Audi-verkstedet, og verkstedet\nvil ikke lenger automatisk ta kontakt med deg i forbindelse med\nservice.", pl_PL="Dane pojazdu nie są już udostępniane dealerowi Audi i nie będzie\nsię on już automatycznie z Tobą kontaktować w przypadku\nserwisowym.", pt_PT="Já não são partilhados dados do veículo com o teu Concessionário\nAudi e ele não entrará automaticamente em contacto em caso de\nserviço.", ro_RO="Nu mai sunt partajate date ale autovehiculului cu partenerul Audi\niar acesta nu vă va mai contacta automat în caz de service.", ru_RU="Данные об автомобиле больше не будут передаваться вашему\nпартнеру Audi, и он больше не будет автоматически\nсвязываться с вами при необходимости проведения\nтехобслуживания.", sk_SK="Údaje o vozidle sa už nebudú zdieľať s vaším partnerom Audi a v\nprípade servisu už nebudete automaticky kontaktovaný.", sl_SI="Podatki o vozilu ne bodo več deljeni z vašim pooblaščenim\npartnerjem Audi. V primeru servisa ne bo več avtomatsko\nvzpostavil stika z vami.", sr_RS="Više se ne dele podaci o vozilu sa vašim Audi partnerom i on vas\nviše neće automatski kontaktirati u slučaju servisa.", sv_SE="Inga fordonsdata kommer att delas med din Audi-partner längre\noch partnern kommer inte längre att kontakta dig automatiskt i\nsamband med service.", tr_TR="Araç verileri artık Audi yetkili servisin ile paylaşılmayacak ve servis\ndurumunda seninle otomatik olarak iletişime geçmeyecektir.", uk_UA="Дані про автомобіль більше не передаватимуться вашому\nпартнеру Audi, і він більше не зв'язуватиметься з вами\nавтоматично, коли виникне потреба в технічному\nобслуговуванні.")
serviceleads_confirmedAppointment_details = TextObject(bs_BA="Potvrđeni termin: %1", cs_CZ="Potvrzený termín: %1", da_DK="Bekræftet tid: %1", de_DE="Bestätigter Termin: %1", el_GR="Επιβεβαιωμένο ραντεβού: %1", en_GB="Confirmed appointment: %1", es_ES="Cita confirmada: %1", fi_FI="Vahvistettu ajanvaraus: %1", fr_FR="Rendez-vous confirmé: %1", hr_HR="Potvrđeni termin: %1", hu_HU="Visszaigazolt időpont: %1", it_IT="Appuntamento confermato: %1", nl_NL="Bevestigde afspraak: %1", no_NO="Bekreftet time: %1", pl_PL="Potwierdzony termin: %1", pt_PT="Marcação confirmada: %1", ro_RO="Dată confirmată: %1", ru_RU="Подтвержденное событие: %1", sk_SK="Potvrdený termín: %1", sl_SI="Potrjeni termin: %1", sr_RS="Potvrđeni termin: %1", sv_SE="Bekräftad tidsbokning: %1", tr_TR="Onaylanmış randevu: %1", uk_UA="Підтверджена зустріч: %1")
