setup_title = TextObject(bs_BA="Postavke", cs_CZ="Nastavení", da_DK="Indstillinger", de_DE="Einstellungen", el_GR="Ρυθμίσεις", en_GB="Settings", es_ES="Ajustes", fi_FI="Asetukset", fr_FR="Réglages", hr_HR="Postavke", hu_HU="Beállítások", it_IT="Impostazioni", nl_NL="Instellingen", no_NO="Innstillinger", pl_PL="Ustawienia", pt_PT="Ajustes", ro_RO="Setare", ru_RU="Настройки", sk_SK="Nastavenia", sl_SI="Nastavitve", sr_RS="Podešavanja", sv_SE="Inställningar", tr_TR="Ayarlar", uk_UA="Настройки")
